# Validação de senha bancária
senha = input("Digite a senha: ")

tem_tamanho_ok = len(senha) >= 6
tem_numero = any(c.isdigit() for c in senha)  # Prévia: usaremos mais em M2

if tem_tamanho_ok:
    print("Comprimento: OK")
else:
    print("Comprimento: INVÁLIDO (mínimo 6 caracteres)")

if not tem_tamanho_ok:
    print("Senha rejeitada.")
else:
    print("Senha aceita.")
